sqlMap.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY F.REGISTERED_AT ASC) AS ROW_NO, F.FILE_NAME, F.FILE_DESCRIPTION, F.STORED_FILE_ID, F.REGISTERED_BY_NAME, F.REGISTERED_AT, M.FILE_MAP_ID, R.STAGE_CODE FROM EXAMPLE_FILE_MAP M, EXAMPLE_STORED_FILE F, EXAMPLE_BOUNDARY_FILE R WHERE M.STORED_FILE_ID = F.STORED_FILE_ID AND M.FILE_MAP_ID = R.FILE_MAP_ID AND R.PROJECT_ID = #projectId# AND R.DOCUMENT_TYPE = #documentType#
AND R.STAGE_CODE = #stageCode#
) ORDER BY ROW_NO DESC
